mapper.select:
SELECT , IFNULL(scr.rating_avg, 0.00) AS rating_avg, IFNULL(scr.rating_count, 0) AS rating_count, rl.score AS user_score, aud.audiences_csv, eq.equipments_csv, ben.benefits_csv FROM sport_course sc LEFT JOIN sport_course_rating scr ON scr.course_id = sc.id LEFT JOIN sport_course_rating_log rl ON rl.course_id = sc.id AND rl.user_id = #{userId} LEFT JOIN () aud ON aud.course_id = sc.id LEFT JOIN () eq ON eq.course_id = sc.id LEFT JOIN () ben ON ben.course_id = sc.id WHERE sc.is_deleted = 0 AND sc.status = 'published'
AND sc.name LIKE CONCAT('%', #{keyword}, '%')
ORDER BY sc.sort_weight DESC, sc.updated_at DESC, sc.id DESC LIMIT #{limit}

SELECT COUNT(1)
FROM sport_course
WHERE name = #{name}
  AND is_deleted = 0

    AND id != #{excludeId}
